export interface FileUpload { // custom file type
  objectURL: string;
  lastModified: number;
  lastModifiedDate: Date;
  name: string;
  size: number;
  type: string;
  webkitRelativePath: string;
}

export interface FileUploadFile extends File { // extended native file type
  lastModifiedDate?: Date;
}

export interface FileUploadErrors {
  [FileUploadError.IncorrectFileType]?: Array<FileUpload>;
  [FileUploadError.MaxFileSize]?: Array<FileUpload>;
  [FileUploadError.MaxFileLimit]?: Array<FileUpload>;
  [FileUploadError.MultipleFiles]?: Array<FileUpload>;
}

export enum FileUploadStatus {
  Default = 0,
  Uploading = 1,
  Failed = 2,
  Success = 3,
  Error = 4,
}

export enum FileUploadError {
  MultipleFiles = 'Multiple-Files',
  MaxFileSize = 'Max-File-Size',
  MaxFileLimit = 'Max-File-Limit',
  IncorrectFileType = 'Incorrect-File-Type'
}

export interface FileUploadTextLink {
  text: string;
  switchToDefaultStatus?: boolean;
  action?: (file: FileUpload | FileUpload[], status: FileUploadStatus) => void;
}
