import { FileUpload } from '@src/mx-components/mx-file-upload/mx-file-upload.model';

const getFileExtension = (file: File): string => '.' + file.name.split('.').pop();

const getTypeClass = (fileType: string): string => fileType.substring(0, fileType.indexOf('/'));

const isWildcard = (fileType: string): boolean => fileType.indexOf('*') !== -1;

export const getFileMessageNamesMax50Chars = (files: Array<FileUpload>): string => {
  const MAX_MESSAGE_LENGTH = 50;
  let currentLength = 0;

  return files ?
    files.reduce( (acc, file, currentIndex, files) => {
      currentLength = acc.length;
      if (currentIndex >= 2) {
        return acc;
      } else if (currentIndex === 1) {
        const attemptedLength = currentLength + file.name.length;
        const newVar = currentIndex !== files.length - 1 ?
          `${acc}, ${file.name} and ${files.length - 2} more` :
          `${acc} and ${file.name}`;
        return attemptedLength < MAX_MESSAGE_LENGTH ? newVar : `${acc} and ${files.length - 1} more`;
      } else {
        return `${file.name}`;
      }
    }, '') :
    '';
};

export const getFileMessageNames = (files: Array<FileUpload>): string => {
  return files ?
    files.reduce( (acc, file, currentIndex, files) => {
      acc += file.name;
      if (currentIndex < files.length - 1) {
        acc += currentIndex === files.length - 2 ? ' and ' : ', ';
      }
      return acc;
    }, '') :
    '';
};

export const convertFileSizeBytesToMB = (fileSize) => fileSize / 1024 / 1024;

export const isAcceptableType = (file: File, type: string): boolean => {
  if (isWildcard(type)) {
    return type === '*' || getTypeClass(file.type) === getTypeClass(type);
  }
  return file.type === type || getFileExtension(file).toLowerCase() === type.toLowerCase();
};

export const convertFileToFileUpload = (file: File): FileUpload => {
  return {
    objectURL: URL.createObjectURL(file),
    lastModified: file.lastModified,
    lastModifiedDate: new Date(file.lastModified),
    name: file.name,
    size: file.size,
    type: file.type,
    webkitRelativePath: file.webkitRelativePath || ''
  };
};

export const convertFilesToFileUploads = (files: File[]): FileUpload[] =>
  files.map((file: File) => convertFileToFileUpload(file));
