import { Component, Event, EventEmitter, Fragment, h, Prop, State, Watch } from '@stencil/core';
import {
  FileUpload,
  FileUploadError,
  FileUploadErrors,
  FileUploadFile,
  FileUploadStatus,
  FileUploadTextLink
} from './mx-file-upload.model';
import { isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';
import { isArray } from '@src/utils/mx-utils';
import {
  convertFileSizeBytesToMB,
  convertFilesToFileUploads,
  convertFileToFileUpload,
  getFileMessageNames, getFileMessageNamesMax50Chars,
  isAcceptableType
} from '@src/utils/mx-utils/file-upload.utils';

type TextLinksObject = {
  fail?: FileUploadTextLink[]
  2?: FileUploadTextLink[]
  success?: FileUploadTextLink[]
  3?: FileUploadTextLink[]
};

const tryAgainLabel: string = 'Please try again.';

@Component({
  tag: 'mx-file-upload',
  styleUrl: 'mx-file-upload.css'
})
export class MxFileUpload {

  /** Determines if compact version of file upload is used. */
  @Prop() readonly isCompact: boolean = false;
  /** @internal Height of the file upload window. Note: This property is now deprecated. */
  @Prop({ mutable: true }) height = 17;
  /** @internal Width of the file upload window. Note: This property is now deprecated. */
  @Prop({ mutable: true }) width = 33.438;
  /** Allowed accepted file type. */
  @Prop() readonly accept: string = '*';
  /** Maximum file size allowed in MB. */
  @Prop() readonly maxFileSize: number = 100; // 100MB
  /** Set the upload state from outside based on backend upload status. */
  @Prop() readonly uploadStatus: FileUploadStatus = FileUploadStatus.Default;
  /** Set wether the user can provide multiple or single files. The filesSelected event will fire when a file is selected when this is set to true. */
  @Prop() readonly multiple: boolean = false;
  /** Maximum number of files a user can upload at a time. Only takes into effect when `multiple` is set to `true`. */
  @Prop() readonly maxFiles?: number;
  /** A function that is returning an array of messages to be displayed on success upload. */
  @Prop() readonly customSuccessMessagesComposer: (inputFile: FileUpload | FileUpload[]) => string[] =
    this.defaultSuccessMessagesComposer;
  /** A function that is returning an array of messages to be displayed on failed upload. */
  @Prop() readonly customFailMessagesComposer: (inputFile: FileUpload | FileUpload[]) => string[] =
    this.defaultFailedMessagesComposer;

  /** Text links for different upload statuses.
   *  This is an JS object. The key can be 'success' or '3' for success text links and
   *  'fail' or '2' for failed text links. The value is an array of objects describing the text link. */
  @Prop() readonly textLinks: TextLinksObject = {};

  @State() _uploadStatus: number = this.uploadStatus;

  @Watch('uploadStatus')
  watchUploadStatus(newUploadStatus: FileUploadStatus) {
    this._uploadStatus = newUploadStatus;
  }

  /** Event when file is selected. */
  @Event() fileSelected: EventEmitter<FileUpload>;

  /** Event when multiple files are selected. */
  @Event() filesSelected: EventEmitter<FileUpload[]>;

  @State() inputFile: FileUpload;
  @State() inputFiles: FileUpload[];
  @State() errorMessages: string[] = [];

  private fileInput!: HTMLInputElement;

  private readonly defaultTextLinks: TextLinksObject = {
    success: [{ text: 'Upload more files' }],
    fail: [{ text: 'Retry' }]
  };

  private defaultSuccessMessagesComposer(inputFile: FileUpload | FileUpload[]): string[] {
    const inputFiles: FileUpload[] = (inputFile || []) as FileUpload[];
    const inputSingleFile: FileUpload = inputFile as FileUpload;
    return isArray(inputFile) ?
      [`${inputFiles.length} file(s) uploaded successfully!`] :
      [`${(inputSingleFile ? inputSingleFile.name : '')}`, 'was uploaded successfully!'];
  }

  private defaultFailedMessagesComposer(inputFile: FileUpload | FileUpload[]): string[] {
    const inputSingleFile: FileUpload = inputFile as FileUpload;
    const singleFileName = inputSingleFile ? inputSingleFile.name : '';
    return [
      isArray(inputFile) ? getFileMessageNames(inputFile as FileUpload[]) : singleFileName,
      'could not be uploaded.',
      tryAgainLabel
    ];
  }

  private readonly clickFileInput = () => this.fileInput.click();

  componentWillLoad() {
    // Deprecation messages for height and width
    if (!isNullOrUndefinedOrEmptyString(this.height) && (this.height !== 17)) {
      console.warn('The height prop is deprecated.');
    }

    if (!isNullOrUndefinedOrEmptyString(this.width) && (this.width !== 33.438)) {
      console.warn('The width prop is deprecated.');
    }

    // If compact override the values
    if(this.isCompact) {
      this.height = 13.5;
      this.width = 18.625;
    }
  }

  private readonly getErrorMessage = (errorMessageTypes: FileUploadErrors | null) => {
    if (errorMessageTypes == null) {
      return [];
    }

    if (errorMessageTypes.hasOwnProperty(FileUploadError.MaxFileSize)) {
      return [
        getFileMessageNames(errorMessageTypes[FileUploadError.MaxFileSize]),
        'could not be uploaded due to file size.',
        this.multiple ? `Max size is ${this.maxFileSize}MB per file.` : `Max size is ${this.maxFileSize}MB.`,
        this.multiple ? 'Please try to upload all files again.' : tryAgainLabel
      ];
    }

    if (errorMessageTypes.hasOwnProperty(FileUploadError.IncorrectFileType)) {
      return [
        getFileMessageNames(errorMessageTypes[FileUploadError.IncorrectFileType]),
        'could not be uploaded due to incorrect file type.',
        `${this.accept} files only.`,
        this.multiple ? 'Please try to upload all files again.' : tryAgainLabel
      ];
    }

    if (errorMessageTypes.hasOwnProperty(FileUploadError.MultipleFiles)) {
      return ['Please upload one file at a time.'];
    }

    if (errorMessageTypes.hasOwnProperty(FileUploadError.MaxFileLimit)) {
      return [`Max ${this.maxFiles} files at a time. Please try again.`];
    }

    return [];
  };

  private isFileTypeValid(file: File): boolean {
    const acceptableTypes: string[] | undefined = this.accept?.split(',').map((type) => type.trim());
  
    if (!acceptableTypes) {
      return false;
    }
  
    return acceptableTypes.some((type) => isAcceptableType(file, type));
  }

  private readonly getErrorMessageType = (files: File[]): FileUploadErrors | null => {
    const fileUploads: FileUpload[] = convertFilesToFileUploads(files);
    if (files.length > 1 && !this.multiple) {
      return { [FileUploadError.MultipleFiles]: fileUploads };
    } else if (files.length > this.maxFiles) {
      return { [FileUploadError.MaxFileLimit]: fileUploads };
    }
    const fileUploadErrors: FileUploadErrors = {};
    files.forEach((file) => {
      const fileUpload: FileUpload = convertFileToFileUpload(file);
      if (convertFileSizeBytesToMB(file.size) > this.maxFileSize) {
        fileUploadErrors[FileUploadError.MaxFileSize] = fileUploadErrors[FileUploadError.MaxFileSize] || [];
        fileUploadErrors[FileUploadError.MaxFileSize].push(fileUpload);
      } else if (!this.isFileTypeValid(file)) {
        fileUploadErrors[FileUploadError.IncorrectFileType] = fileUploadErrors[FileUploadError.IncorrectFileType] || [];
        fileUploadErrors[FileUploadError.IncorrectFileType].push(fileUpload);
      }
    });

    return Object.keys(fileUploadErrors).length > 0 ? fileUploadErrors : null;
  };

  private handleFiles = (files: Array<FileUploadFile>) => {
    if (files && files.length > 0) {
      const errorMessageTypes: FileUploadErrors | null = this.getErrorMessageType(files);
      this.errorMessages = this.getErrorMessage(errorMessageTypes);
      if (this.errorMessages.length > 0) {
        this._uploadStatus = FileUploadStatus.Error;
      } else if (this.multiple) {
        this.inputFiles = convertFilesToFileUploads(files);
        this.filesSelected.emit(this.inputFiles);
      } else {
        this.inputFile = convertFileToFileUpload(files[0]);
        this.fileSelected.emit(this.inputFile);
      }
    }
  };

  private handleFilesChange = (event: Event) => {
    const input = event.target as HTMLInputElement;
    const files: FileList = input.files;
    const iterableFiles: Array<FileUploadFile> = [];
    for (let i = 0; i < files.length; i++) {
      iterableFiles.push(files[i]);
    }
    this.handleFiles(iterableFiles);
  };

  private handleFilesDrop = (event: any) => {
    const files: FileList = event.detail;
    let iterableFiles: Array<FileUploadFile> = [];
    for( let i = 0; i < files.length; i++) {
      iterableFiles.push(files[i]);
    }
    this.handleFiles(iterableFiles);
  }

  private renderDropZoneAfterUpload(
    dropZoneCssClasses: string,
    messagesComposer: (inputFile: FileUpload | FileUpload[]) => string[],
    icon: string,
    textLinkCssClass: string,
    textLinks,
    maxLines) {
    return <mx-file-upload-dropzone
      class={dropZoneCssClasses}
      isCompact={this.isCompact}
      height={this.height}
      width={this.width}>
      { h(icon, { class: { 'mb-8': true }, size: this.isCompact ? 'l' : 'xl' }) }
      {
        <Fragment>
          {
            messagesComposer(this.multiple ? this.inputFiles : this.inputFile)
              .slice(0, maxLines)
              .map((message, index) => <p key={index} title={message}>{message}</p>)
          }
        </Fragment>
      }
      <div class='mx-file-upload__text-links-container'>
        {
          textLinks.slice(0, 2).map((textLink: FileUploadTextLink, index: number) => (
            <kds-link
              key={index}
              class='mt-8'
              href=''
              linkClass={textLinkCssClass}
              size={this.isCompact ? 's' : 'l'}
              onClick={(e) => {
                e.preventDefault();
                if (textLink.action) {
                  textLink.action(this.multiple ? this.inputFiles : this.inputFile, this._uploadStatus);
                }
                if (!textLink.hasOwnProperty('switchToDefaultStatus') || textLink.switchToDefaultStatus) {
                  this._uploadStatus = FileUploadStatus.Default;
                }
              }}>{textLink.text}</kds-link>
          ))
        }
      </div>
    </mx-file-upload-dropzone>;
  }

  render() {
    const textLinks: TextLinksObject = {
      ...this.defaultTextLinks,
      ...this.textLinks
    };

    if (this._uploadStatus == FileUploadStatus.Uploading) {
      const fileMessageNames: string = getFileMessageNames(this.inputFiles);
      const fileMessageNamesMax50Chars: string = getFileMessageNamesMax50Chars(this.inputFiles);
      return (
        <mx-file-upload-dropzone
          class='mx-file-upload__loading border-neutral-least-prominent bg-neutral-most-subtle'
          height={this.height}
          width={this.width}
          isCompact={this.isCompact}>
          <p class='body-l'>Uploading</p>
          { !this.multiple  && <kds-loading-spinner size='l' label={this.inputFile?.name} /> }
          <div class='mx-file-upload__uploading-files-list'>
            {
              this.multiple &&
                <kds-loading-spinner size='l' title={ fileMessageNames } label={ fileMessageNamesMax50Chars } />
            }
          </div>
        </mx-file-upload-dropzone>
      );
    }


    if (this._uploadStatus == FileUploadStatus.Error) {
      return this.renderDropZoneAfterUpload(
        `mx-file-upload__error
            text-negative-less-prominent
            border-negative-less-prominent
            bg-negative-most-subtle`,
        () => this.errorMessages,
        'kds-icon-error',
        'text-negative-less-prominent',
        this.defaultTextLinks.fail,
        4);
    }

    if (this._uploadStatus == FileUploadStatus.Failed) {
      return this.renderDropZoneAfterUpload(
        `mx-file-upload__error
        text-negative-less-prominent
        border-negative-less-prominent
        bg-negative-most-subtle`,
        this.customFailMessagesComposer,
        'kds-icon-error',
        'text-negative-less-prominent',
        textLinks[2] || textLinks.fail,
        3);
    }

    if (this._uploadStatus == FileUploadStatus.Success) {
      return this.renderDropZoneAfterUpload(
        `mx-file-upload__success
            text-positive-less-prominent
            border-positive-less-prominent
            bg-positive-most-subtle`,
        this.customSuccessMessagesComposer,
        'kds-icon-success',
        'text-positive-less-prominent',
        textLinks[3] || textLinks.success,
        3);
    }

    return (
      <div class='mx-file-upload__container'>
        <mx-file-upload-dropzone
          class='mx-file-upload__panel border-neutral-least-prominent bg-neutral-most-subtle'
          onHandleFiles={this.handleFilesDrop}
          height={this.height}
          width={this.width}
          isCompact={this.isCompact}>
          <span class='heading-s text-primary'>
            <kds-icon-upload /> Drag and drop
          </span>

          <p class={{ 'text-primary body-xs': true, 'py-8': this.isCompact }}>or</p>

          <kds-button
            palette='brand'
            kind='dominant'
            variant='border'
            type='button'
            compact={this.isCompact}
            buttonClass='rounded-extra-large mx-file-upload__kds-button'
            onClick={this.clickFileInput}>
            Browse files
          </kds-button>

          <input
            ref={(el: HTMLInputElement) => this.fileInput = el}
            type='file'
            class='screen-reader'
            multiple={this.multiple}
            accept={this.accept}
            onClick={(e: any) => e.target.value = null} // Clear the input value on click
            onChange={this.handleFilesChange} />

          <div class='text-secondary mx-file-upload__info'>
            <p class='mt-12'>
              {this.accept === '*' ? "All file types accepted. " : `${this.accept} files only. `}
              Max size {this.maxFileSize}MB{this.multiple ? ' per file' : ''}.
            </p>
            <p class='mt-4'>
              {
                this.multiple
                  ? `Multiple files allowed.${this.maxFiles ? ` Max ${this.maxFiles} files at a time.`: ''}`
                  : 'Upload one file at a time.'
              }
            </p>
          </div>
        </mx-file-upload-dropzone>
      </div>
    );
  }
}
